Java.perform(function () {
    var ListMenuItemView = Java.use('androidx.appcompat.view.menu.ListMenuItemView');
    var MenuItemImpl = Java.use('androidx.appcompat.view.menu.MenuItemImpl');

    ListMenuItemView.initialize.implementation = function (menuItemImpl, i2) {
        // Call the original method
