            var title = menuItemImpl.getTitleForItemView(this) ? menuItemImpl.getTitleForItemView(this).toString() : "N/A";
            var shortcut = menuItemImpl.getShortcutLabel() ? menuItemImpl.getShortcutLabel().toString() : "N/A";
            var isCheckable = menuItemImpl.isCheckable();
            var isChecked = menuItemImpl.isChecked();
            var hasSubMenu = menuItemImpl.hasSubMenu();
            var isVisible = menuItemImpl.isVisible();
            var isEnabled = menuItemImpl.isEnabled();
            // You can also try to get the item ID, though it might be protected or not directly accessible
